 28→/** Limit text to maxLines while preserving newlines. Appends "…" if truncated. */
 29→function limitLines(text: string, maxLines: number): string {
 30→  const lines = text.split("\n");
 31→  if (lines.length <= maxLines) return text;
 32→  return lines.slice(0, maxLines).join("\n") + "\n…(" + (lines.length - maxLines) + " more lines)";
 33→}
 34→
 35→/** Clamp each line to maxWidth so bordered boxes don't overflow the terminal. */
 36→function clampLines(text: string, maxWidth: number): string {
 37→  return text
 38→    .split("\n")
 39→    .map((line) => (line.length > maxWidth ? line.slice(0, maxWidth - 1) + "…" : line))
 40→    .join("\n");
 41→}
