104→/**
105→ * Returns context window usage percentage (0-100).
106→ * Returns -1 if no usage data is available.
107→ */
108→export function contextPercent(msgs: DisplayMessage[]): number {
109→  const contextWindowSize = 1_000_000;
110→  for (let i = msgs.length - 1; i >= 0; i--) {
111→    if (msgs[i].role === "claude" && msgs[i].context_tokens > 0) {
112→      const pct = Math.floor((msgs[i].context_tokens * 100) / contextWindowSize);
113→      return Math.min(pct, 100);
114→    }
115→  }
116→  return -1;
117→}
