178→/**
179→ * Truncates text to maxLen, appending ellipsis if needed.
180→ */
181→export function truncate(text: string, maxLen: number): string {
182→  if (text.length <= maxLen) return text;
183→  return text.slice(0, maxLen - 1) + "\u2026";
184→}
