 87→ * Returns a human-readable label for a permission mode.
 88→ */
 89→export function shortMode(mode: string): string {
 90→  switch (mode) {
 91→    case "default":
 92→      return "default";
 93→    case "acceptEdits":
 94→      return "auto-edit";
