119→/**
120→ * Formats a timestamp as yyyy-mm-dd hh:mm:ss.
121→ */
122→export function formatExactTime(ts: string): string {
123→  if (!ts) return "";
124→  try {
125→    const d = new Date(ts);
126→    if (isNaN(d.getTime())) return "";
127→    const yyyy = d.getFullYear();
128→    const mm = String(d.getMonth() + 1).padStart(2, "0");
129→    const dd = String(d.getDate()).padStart(2, "0");
130→    const hh = String(d.getHours()).padStart(2, "0");
131→    const mi = String(d.getMinutes()).padStart(2, "0");
132→    const ss = String(d.getSeconds()).padStart(2, "0");
133→    return `${yyyy}-${mm}-${dd} ${hh}:${mi}:${ss}`;
134→  } catch {
135→    return "";
136→  }
137→}
138→
139→/**
140→ * Groups sessions by date category, sorted by mod_time descending within each group.
141→ */
142→export function groupByDate<T extends { mod_time: string }>(
143→  items: T[],
144→): { category: string; items: T[] }[] {
145→  const now = new Date();
146→  const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate());
147→  const yesterdayStart = new Date(todayStart.getTime() - 86400000);
148→  const weekStart = new Date(todayStart.getTime() - 7 * 86400000);
149→  const monthStart = new Date(todayStart.getTime() - 30 * 86400000);
150→
151→  const groups: Record<string, T[]> = {};
152→  const order = ["Today", "Yesterday", "This Week", "This Month", "Older"];
153→
154→  for (const item of items) {
155→    const d = new Date(item.mod_time);
156→    let cat: string;
157→    if (d >= todayStart) cat = "Today";
158→    else if (d >= yesterdayStart) cat = "Yesterday";
159→    else if (d >= weekStart) cat = "This Week";
160→    else if (d >= monthStart) cat = "This Month";
161→    else cat = "Older";
162→
163→    (groups[cat] ??= []).push(item);
164→  }
165→
166→  // Sort each group by mod_time descending (most recent first)
167→  for (const cat of order) {
168→    if (groups[cat]) {
169→      groups[cat].sort((a, b) => new Date(b.mod_time).getTime() - new Date(a.mod_time).getTime());
170→    }
171→  }
172→
173→  return order
174→    .filter((cat) => groups[cat]?.length)
175→    .map((category) => ({ category, items: groups[category] }));
176→}
