  --icon-bash: #9a8aef;
  --icon-web: #5fafff;
  --icon-mcp: #af5fff;
  --icon-cron: #8a8aaa;
  --icon-git: #af5fff;

  /* Agent panel */
  --agent-panel: #63b3ed;

  /* Misc */
  --scrollbar-thumb: #444466;
  --scrollbar-track: transparent;
}

