/* ---- Reset & Base ---- */

*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html,
body,
#root {
  height: 100%;
  overflow: hidden;
}

body {
  font-family:
    "JetBrains Mono", "SF Mono", "Fira Code", "Cascadia Code", "Consolas", ui-monospace, monospace;
  font-size: 13px;
  line-height: 1.5;
  color: var(--text-primary);
  background-color: var(--bg);
  -webkit-font-smoothing: antialiased;
}

/* ---- Scrollbar ---- */

::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}

::-webkit-scrollbar-track {
  background: var(--scrollbar-track);
}

::-webkit-scrollbar-thumb {
  background: var(--scrollbar-thumb);
  border-radius: 3px;
}

::-webkit-scrollbar-thumb:hover {
  background: var(--border);
}

/* ---- App Layout ---- */

.app {
  display: flex;
  flex-direction: column;
  height: 100vh;
  overflow: hidden;
}

.app-body {
  display: flex;
  flex: 1;
  min-height: 0;
  overflow: hidden;
}

.main-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  min-width: 0;
  overflow: hidden;
}

/* ---- Resize Handle ---- */

.resize-handle {
  flex-shrink: 0;
  background: transparent;
  position: relative;
  z-index: 5;
}

.resize-handle--horizontal {
  width: 5px;
  cursor: col-resize;
  margin: 0 -2px;
}

.resize-handle--horizontal::after {
  content: "";
  position: absolute;
  top: 0;
  bottom: 0;
  left: 2px;
  width: 1px;
  background: var(--border);
  transition: background 0.15s;
}

.resize-handle--horizontal:hover::after,
.resize-handle--horizontal:active::after {
  background: var(--accent);
  width: 2px;
  left: 1px;
}

.resize-handle--vertical {
  height: 5px;
  cursor: row-resize;
  margin: -2px 0;
}

.resize-handle--vertical::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  top: 2px;
  height: 1px;
  background: var(--border);
  transition: background 0.15s;
}

.resize-handle--vertical:hover::after,
.resize-handle--vertical:active::after {
  background: var(--accent);
  height: 2px;
  top: 1px;
}

/* ---- Project Tree Sidebar ---- */

.project-tree {
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  background: var(--bg);
  overflow: hidden;
}

.project-tree__header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 8px 12px;
  font-size: 11px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: var(--dim);
  border-bottom: 1px solid var(--border);
}

.project-tree__refresh {
  background: none;
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  font-size: 14px;
  display: inline-flex;
  align-items: center;
  padding: 2px 4px;
  border-radius: 3px;
  line-height: 1;
  transition: color 0.15s;
}

.project-tree__refresh:hover {
  color: var(--text);
  background: var(--bg-hover);
}

.project-tree__refresh--spinning {
  animation: spin 0.8s linear infinite;
}

@keyframes spin {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

.project-tree__list {
  flex: 1;
  overflow-y: auto;
  padding: 4px 0;
}

.project-tree__item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 5px 12px;
  cursor: pointer;
  font-size: 12px;
  color: var(--fg);
  border-left: 2px solid transparent;
  min-width: 0;
}

.project-tree__item:hover {
  background: var(--hover);
}

.project-tree__item--selected {
  background: var(--hover);
  border-left-color: var(--accent);
  color: var(--accent);
}

.project-tree__item--highlighted {
  background: var(--bg-hover);
  outline: 1px solid var(--accent);
  outline-offset: -1px;
}

.project-tree--focused {
  outline: 1px solid var(--accent);
  outline-offset: -1px;
}

.project-tree__name {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  min-width: 0;
}

.project-tree__meta {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-shrink: 0;
  margin-left: 6px;
}

.project-tree__count {
  font-size: 10px;
  color: var(--dim);
  background: var(--border);
  padding: 0 5px;
  border-radius: 8px;
  line-height: 16px;
}

/* ---- Shared ongoing dots indicator ---- */

.ongoing-dots {
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

.ongoing-dot {
  display: inline-block;
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--ongoing);
  animation: pulse 1.5s ease-in-out infinite;
}

.ongoing-dots > :nth-child(2) {
  animation-delay: 0.15s;
}

.ongoing-dots > :nth-child(3) {
  animation-delay: 0.3s;
}

.ongoing-dots > :nth-child(4) {
  animation-delay: 0.45s;
}

.ongoing-dots > :nth-child(5) {
  animation-delay: 0.6s;
}

.project-tree__item--child {
  font-size: 11px;
  opacity: 0.85;
}

.project-tree__branch {
  color: var(--text-dim);
  font-size: 10px;
}

.project-tree__item--group {
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: var(--text-secondary);
  cursor: default;
}

.project-tree__item--group:hover {
  background: transparent;
}

.project-tree__group-icon {
  display: inline-flex;
  align-items: center;
  vertical-align: middle;
  font-size: 13px;
  margin-right: 4px;
}

/* ---- Info Bar ---- */

.info-bar {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 6px 16px;
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  min-height: 36px;
  min-width: 0;
}

.info-bar__project {
  font-weight: 600;
  color: var(--text-primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}

.info-bar__session-id {
  color: var(--dim);
  font-size: 11px;
  font-family: var(--font-mono, monospace);
  opacity: 0.6;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
}

.info-bar__branch {
  color: var(--git-branch);
  font-size: 12px;
}

.info-bar__branch--dirty::after {
  content: " *";
  color: var(--context-warn);
}

.info-bar__pill {
  display: inline-flex;
  align-items: center;
  padding: 1px 8px;
  border-radius: 10px;
  font-size: 11px;
  font-weight: 600;
  color: #fff;
}

.info-bar__pill--bypass {
  background: var(--pill-bypass);
}

.info-bar__pill--acceptEdits {
  background: var(--pill-accept-edits);
}

.info-bar__pill--plan {
  background: var(--pill-plan);
}

.info-bar__pill--default {
  background: var(--text-muted);
}

.info-bar__context {
  display: flex;
  align-items: center;
  gap: 6px;
  margin-left: auto;
  font-size: 11px;
  color: var(--text-dim);
  flex-shrink: 0;
}

.info-bar__context-bar {
  width: 60px;
  height: 6px;
  background: var(--bg);
  border-radius: 3px;
  overflow: hidden;
}

.info-bar__context-fill {
  height: 100%;
  border-radius: 3px;
  transition: width 0.3s ease;
}

.info-bar__tokens {
  color: var(--text-secondary);
  font-size: 12px;
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.info-bar__cost {
  color: var(--error);
  font-size: 12px;
  font-weight: 600;
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.info-bar__ongoing {
  display: flex;
  align-items: center;
  gap: 4px;
  color: var(--ongoing);
  font-size: 12px;
  animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

@keyframes spin {
  to {
    transform: rotate(360deg);
  }
}

/* Pure-CSS braille spinner — replaces the JS animFrame approach */
.braille-spinner::after {
  content: "\280B";
  animation: braille-spin 1s steps(10, end) infinite;
}

@keyframes braille-spin {
  0% {
    content: "\280B";
  }
  10% {
    content: "\2819";
  }
  20% {
    content: "\2839";
  }
  30% {
    content: "\2838";
  }
  40% {
    content: "\283C";
  }
  50% {
    content: "\2834";
  }
  60% {
    content: "\2826";
  }
  70% {
    content: "\2827";
  }
  80% {
    content: "\2807";
  }
  90% {
    content: "\280F";
  }
}

/* ---- View Toolbar ---- */

.view-toolbar {
  display: flex;
  align-items: center;
  gap: 4px;
  padding: 2px 16px;
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  min-height: 30px;
}

.view-toolbar__btn {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 2px 10px;
  height: 24px;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: 3px;
  color: var(--text-primary);
  font-family: inherit;
  font-size: 11px;
  font-weight: 500;
  cursor: pointer;
  transition:
    background 0.1s,
    border-color 0.1s;
  white-space: nowrap;
}

.view-toolbar__btn:hover {
  background: var(--bg-hover);
  border-color: var(--accent);
  color: var(--accent);
}

.view-toolbar__btn:disabled {
  opacity: 0.4;
  cursor: default;
}

.view-toolbar__btn:disabled:hover {
  background: var(--bg-elevated);
  border-color: var(--border);
  color: var(--text-primary);
}

.view-toolbar__btn--active {
  background: var(--accent);
  border-color: var(--accent);
  color: #fff;
}

.view-toolbar__spacer {
  flex: 1;
}

.view-toolbar__separator {
  width: 1px;
  height: 16px;
  background: var(--border);
  margin: 0 4px;
  flex-shrink: 0;
}

/* ---- Keybind Bar ---- */

.keybind-bar {
  display: flex;
  flex-wrap: wrap;
  gap: 4px 12px;
  padding: 4px 16px;
  background: var(--bg-surface);
  border-top: 1px solid var(--border);
  flex-shrink: 0;
  font-size: 11px;
}

.keybind-bar__item {
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

.keybind-bar__key {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 18px;
  padding: 0 4px;
  height: 18px;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: 3px;
  font-size: 10px;
  font-weight: 600;
  color: var(--text-primary);
}

.keybind-bar__label {
  color: var(--text-dim);
}

.keybind-bar__item--clickable {
  cursor: pointer;
  border-radius: 3px;
  padding: 1px 4px;
  transition: background 0.1s;
}

.keybind-bar__item--clickable:hover {
  background: var(--bg-hover);
}

.keybind-bar__item--clickable:hover .keybind-bar__label {
  color: var(--accent);
}

.keybind-bar__toggle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 20px;
  height: 20px;
  margin-left: auto;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: 3px;
  color: var(--text-dim);
  font-family: inherit;
  font-size: 11px;
  font-weight: 600;
  cursor: pointer;
  transition:
    background 0.1s,
    color 0.1s;
  flex-shrink: 0;
}

.keybind-bar__toggle:hover {
  background: var(--bg-hover);
  color: var(--accent);
  border-color: var(--accent);
}

/* ---- Session Picker ---- */

.picker {
  display: flex;
  flex-direction: column;
  height: 100%;
  min-height: 0;
  overflow: hidden;
}

.picker__header {
  padding: 12px 16px;
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.picker__title {
  display: flex;
  align-items: center;
  gap: 12px;
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: 8px;
}

.picker__total-tokens {
  font-size: 12px;
  font-weight: 400;
  color: var(--text-secondary);
}

.picker__total-cost {
  font-size: 12px;
  font-weight: 600;
  color: var(--error);
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.picker__session-stat--cost {
  color: var(--error);
  font-weight: 600;
}

.picker__back-btn {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 2px 10px;
  height: 24px;
  background: var(--bg-elevated);
  border: 1px solid var(--border);
  border-radius: 3px;
  color: var(--accent);
  font-family: inherit;
  font-size: 11px;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.1s;
}

.picker__back-btn:hover {
  background: var(--bg-hover);
  text-decoration: underline;
}

.picker__search {
  width: 100%;
  padding: 6px 10px;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 4px;
  color: var(--text-primary);
  font-family: inherit;
  font-size: 12px;
  outline: none;
}

.picker__search:focus {
  border-color: var(--accent);
}

.picker__search::placeholder {
  color: var(--text-muted);
}

.picker__list {
  flex: 1;
  overflow-y: auto;
  padding: 8px 0;
}

.picker__group-header {
  padding: 8px 16px 4px;
  font-size: 11px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.picker__session {
  display: flex;
  flex-direction: column;
  padding: 8px 16px;
  cursor: pointer;
  border-left: 3px solid transparent;
  transition: background 0.1s;
}

.picker__session:hover {
  background: var(--bg-hover);
}

.picker__session--selected {
  background: var(--picker-selected-bg);
  border-left-color: var(--accent);
}

.picker__session--ongoing {
  border-left-color: var(--ongoing);
  background: rgba(95, 175, 0, 0.06);
}

.picker__session--ongoing.picker__session--selected {
  border-left-color: var(--ongoing);
  background: rgba(95, 175, 0, 0.12);
}

.picker__session-top {
  display: flex;
  align-items: center;
  gap: 8px;
  min-width: 0;
}

.picker__session-icon {
  flex-shrink: 0;
  display: inline-flex;
  align-items: center;
  font-size: 14px;
  color: var(--icon-claude);
}

.picker__session-preview {
  flex: 1;
  min-width: 0;
  color: var(--text-primary);
  font-size: 12px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.picker__session-ongoing {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  padding: 1px 8px;
  border-radius: 3px;
  background: rgba(95, 175, 0, 0.2);
  color: var(--ongoing);
  font-size: 10px;
  font-weight: 700;
  letter-spacing: 0.5px;
  flex-shrink: 0;
}

.picker__session-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 2px;
  font-size: 11px;
  color: var(--text-dim);
  min-width: 0;
}

.picker__session-model {
  font-weight: 600;
}

.picker__session-stat {
  display: inline-flex;
  align-items: center;
  gap: 2px;
}

.picker__session-time {
  margin-left: auto;
  color: var(--text-secondary);
  font-size: 11px;
  flex-shrink: 0;
}

.picker__empty {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 200px;
  color: var(--text-muted);
  font-size: 13px;
}

.picker__loading {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 24px;
  color: var(--text-dim);
}

.session-loading {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 48px 24px;
  color: var(--text-dim);
  height: 100%;
}

/* ---- Message List ---- */

.message-list {
  flex: 1;
  overflow-y: auto;
  padding: 8px 0;
  scroll-behavior: smooth;
}

.message-list__empty {
  display: flex;
  align-items: center;
  justify-content: center;
  height: 100%;
  color: var(--text-muted);
  font-size: 14px;
}

/* ---- Message Item ---- */

.message {
  padding: 8px 16px;
  border-left: 3px solid transparent;
  border-bottom: 1px solid var(--border);
  cursor: pointer;
  transition: background 0.1s;
}

.message:hover {
  background: var(--bg-hover);
}

.message--selected {
  background: var(--bg-elevated);
  border-left-color: var(--accent);
}

.message--user {
  border-left-color: var(--accent);
}

.message--claude {
  border-left-color: var(--text-dim);
}

.message--system {
  border-left-color: var(--text-muted);
  opacity: 0.8;
}

.message--system-error {
  border-left-color: var(--error);
}

.message--compact {
  border-left-color: var(--text-muted);
  opacity: 0.6;
  padding: 4px 16px;
}

.message__header {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 4px;
  min-width: 0;
}

.message__role-icon {
  font-size: 14px;
  flex-shrink: 0;
  display: inline-flex;
  align-items: center;
}

.message__claude-icon {
  width: 14px;
  height: 14px;
}

.message__role {
  font-weight: 600;
  font-size: 12px;
}

.message__role--user {
  color: var(--accent);
}

.message__role--claude {
  color: var(--text-secondary);
}

.message__role--system {
  color: var(--text-muted);
}

.message__model {
  font-size: 11px;
  font-weight: 600;
}

.message__timestamp {
  font-size: 11px;
  color: var(--text-secondary);
  margin-left: auto;
}

.message__detail-btn {
  font-size: 11px;
  padding: 1px 8px;
  border: 1px solid var(--border);
  border-radius: 4px;
  background: var(--bg-secondary);
  color: var(--accent);
  cursor: pointer;
  flex-shrink: 0;
  display: inline-flex;
  align-items: center;
  gap: 2px;
}

.message__detail-btn:hover {
  background: var(--accent);
  color: var(--bg);
}

.message__content {
  font-size: 12px;
  color: var(--text-secondary);
  white-space: pre-wrap;
  word-break: break-word;
  overflow: hidden;
}

.message__content--collapsed {
  max-height: calc(12px * 1.5 * 12); /* ~12 lines */
  overflow: hidden;
  position: relative;
}

.message__content--collapsed::after {
  content: "";
  position: absolute;
  bottom: 0;
  left: 0;
  right: 0;
  height: 2em;
  background: linear-gradient(transparent, var(--bg));
  pointer-events: none;
}

.message--selected .message__content--collapsed::after {
  background: linear-gradient(transparent, var(--bg-elevated));
}

.message__stats {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 10px;
  margin-top: 4px;
  font-size: 11px;
  color: var(--text-dim);
  min-width: 0;
}

.message__stat {
  display: inline-flex;
  align-items: center;
  gap: 3px;
}

.message__stat--tokens-high {
  color: var(--token-high);
}

.message__stat--agents {
  color: var(--agent-panel);
}

.message__stat-icon {
  display: inline-flex;
  align-items: center;
  font-size: 13px;
}

.message__expand-hint {
  color: var(--text-muted);
  font-size: 11px;
}

/* ---- Compact separator ---- */

.compact-separator {
  padding: 2px 16px;
  text-align: center;
  color: var(--text-muted);
  font-size: 11px;
}

.compact-separator__line {
  display: flex;
  align-items: center;
  gap: 8px;
}

.compact-separator__rule {
  flex: 1;
  height: 1px;
  background: var(--border);
}

/* ---- Message Detail ---- */

.message-detail {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.message-detail__header {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 16px;
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  min-width: 0;
}

.message-detail__back {
  display: flex;
  align-items: center;
  gap: 4px;
  color: var(--accent);
  cursor: pointer;
  font-size: 12px;
  background: none;
  border: none;
  font-family: inherit;
}

.message-detail__back:hover {
  text-decoration: underline;
}

.message-detail__title {
  font-weight: 600;
  font-size: 13px;
}

.message-detail__meta {
  font-size: 11px;
  color: var(--text-secondary);
  margin-left: auto;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  min-width: 0;
  flex-shrink: 1;
}

.message-detail__body {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
  min-width: 0;
}

.message-detail__content {
  max-width: 900px;
  margin: 0 auto;
  min-width: 0;
}

.agent-panel .message-detail__content {
  max-width: none;
}

.message-detail__ongoing {
  display: flex;
  justify-content: center;
  padding: 16px 0;
}

.message-detail__text {
  font-size: 13px;
  line-height: 1.6;
  white-space: pre-wrap;
  word-break: break-word;
  margin-bottom: 16px;
}

/* Markdown rendering */
.message-detail__text h1,
.message-detail__text h2,
.message-detail__text h3 {
  color: var(--text-primary);
  margin: 16px 0 8px;
}

.message-detail__text code {
  background: var(--bg-elevated);
  padding: 1px 4px;
  border-radius: 3px;
  font-size: 12px;
}

.message-detail__text pre {
  background: var(--bg-elevated);
  padding: 12px;
  border-radius: 4px;
  overflow-x: auto;
  margin: 8px 0;
}

.message-detail__text pre code {
  background: none;
  padding: 0;
}

.message-detail__text a {
  color: var(--accent);
}

.message-detail__text blockquote {
  border-left: 3px solid var(--border);
  padding-left: 12px;
  color: var(--text-dim);
  margin: 8px 0;
}

.message-detail__text ul,
.message-detail__text ol {
  padding-left: 20px;
  margin: 4px 0;
}

/* ---- Detail Items ---- */

.detail-items {
  margin-top: 8px;
}

.detail-items__section-label {
  font-size: 11px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin: 16px 0 8px;
}

.detail-item {
  border: 1px solid var(--border);
  border-radius: 4px;
  margin-bottom: 6px;
  overflow: hidden;
}

.detail-item--selected {
  border-color: var(--accent);
}

.detail-item--error {
  border-color: var(--error);
}

.detail-item > .message__stats {
  padding: 2px 10px 6px;
}

.detail-item__header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 10px;
  cursor: pointer;
  background: var(--bg-surface);
  transition: background 0.1s;
  min-width: 0;
}

.detail-item__header:hover {
  background: var(--bg-hover);
}

.detail-item__chevron {
  font-size: 10px;
  flex-shrink: 0;
  width: 12px;
  transition: transform 0.15s;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.detail-item__chevron--expanded {
  transform: rotate(90deg);
}

.detail-item__icon {
  font-size: 13px;
  flex-shrink: 0;
  display: inline-flex;
  align-items: center;
}

.detail-item__claude-icon {
  width: 13px;
  height: 13px;
}

.detail-item__name {
  font-weight: 600;
  font-size: 12px;
  color: var(--text-primary);
  flex-shrink: 0;
}

.detail-item__summary {
  flex: 1;
  min-width: 0;
  font-size: 11px;
  color: var(--text-dim);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.detail-item__right {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 11px;
  color: var(--text-dim);
  flex-shrink: 0;
}

.detail-item__duration {
  color: var(--text-muted);
}

.detail-item__tokens {
  color: var(--text-dim);
}

.detail-item__agent-id {
  color: var(--dim);
  font-size: 11px;
  font-family: var(--font-mono, monospace);
  opacity: 0.6;
  flex-shrink: 1;
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.detail-item__body {
  padding: 10px;
  border-top: 1px solid var(--border);
  font-size: 12px;
  min-width: 0;
  overflow: hidden;
}

.detail-item__section {
  margin-bottom: 10px;
}

.detail-item__section:last-child {
  margin-bottom: 0;
}

.detail-item__section-title {
  font-size: 10px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 4px;
}

.detail-item__text {
  white-space: pre-wrap;
  word-break: break-word;
  color: var(--text-secondary);
  max-height: 400px;
  overflow-y: auto;
}

.detail-item__text--error {
  color: var(--error);
}

.detail-item__text--thinking {
  color: var(--text-dim);
  font-style: italic;
}

.detail-item__text--mono {
  font-family: var(--font-mono);
  font-size: 12px;
  opacity: 0.8;
}

.detail-item__json {
  background: var(--bg);
  padding: 8px;
  border-radius: 3px;
  overflow-x: auto;
  max-height: 300px;
  overflow-y: auto;
}

.detail-item__subagent-badge {
  display: inline-flex;
  align-items: center;
  gap: 4px;
  padding: 1px 6px;
  border-radius: 3px;
  background: var(--bg-elevated);
  font-size: 10px;
  color: var(--accent);
}

.detail-item__orphan-badge {
  display: inline-flex;
  align-items: center;
  padding: 1px 5px;
  border-radius: 3px;
  background: var(--warning, #b8860b);
  color: var(--bg);
  font-size: 9px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  opacity: 0.85;
}

.detail-item__prompt-preview {
  padding: 2px 8px 2px 24px;
  font-size: 11px;
  color: var(--text-muted);
  opacity: 0.5;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  cursor: pointer;
}

.detail-item__prompt-preview:hover {
  opacity: 0.8;
}

.detail-item__prompt-preview--expanded {
  opacity: 0.7;
  border-top: 1px solid var(--border);
  padding-top: 4px;
}

.detail-item__popout-btn {
  background: none;
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  font-size: 13px;
  padding: 0 4px;
  border-radius: 3px;
  line-height: 1;
  display: inline-flex;
  align-items: center;
}

.detail-item__popout-btn:hover {
  color: var(--accent);
  background: var(--bg-hover);
}

/* ---- Popout Modal ---- */

.popout-overlay {
  position: fixed;
  inset: 0;
  z-index: 1000;
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
}

.popout-modal {
  position: relative;
  display: flex;
  flex-direction: column;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 8px;
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.5);
  overflow: hidden;
  max-width: 95vw;
  max-height: 95vh;
}

.popout-modal__header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 16px;
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
  min-width: 0;
}

.popout-modal__icon {
  font-size: 14px;
}

.popout-modal__name {
  font-weight: 600;
  color: var(--text-primary);
}

.popout-modal__summary {
  color: var(--text-secondary);
  font-size: 12px;
}

.popout-modal__agent-id {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-dim);
}

.popout-modal__right {
  margin-left: auto;
  display: flex;
  gap: 10px;
  font-size: 11px;
  color: var(--text-secondary);
}

.popout-modal__close {
  margin-left: auto;
  background: none;
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  font-size: 18px;
  padding: 2px 6px;
  border-radius: 3px;
  display: inline-flex;
  align-items: center;
}

.popout-modal__close:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.popout-modal__body {
  flex: 1;
  overflow: auto;
  padding: 4px 0;
  min-height: 0;
  min-width: 0;
}

.popout-modal__body .detail-item__body {
  max-height: none;
  overflow: visible;
  width: 100%;
  box-sizing: border-box;
}

.popout-modal__body .detail-item__text {
  max-height: none;
  overflow: visible;
  white-space: pre-wrap;
  word-break: break-word;
}

.popout-modal__body .detail-item__json {
  max-height: none;
  overflow: visible;
}

.popout-modal__body .detail-item__json pre {
  white-space: pre-wrap;
  word-break: break-word;
}

.popout-modal__body .detail-item__section {
  width: 100%;
  min-width: 0;
}

.popout-modal__resize-handle {
  position: absolute;
  right: 0;
  bottom: 0;
  width: 16px;
  height: 16px;
  cursor: nwse-resize;
}

.popout-modal__resize-handle::after {
  content: "";
  position: absolute;
  right: 3px;
  bottom: 3px;
  width: 8px;
  height: 8px;
  border-right: 2px solid var(--text-dim);
  border-bottom: 2px solid var(--text-dim);
  opacity: 0.5;
}

/* ---- Team Board ---- */

.team-board {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.team-board__header {
  padding: 12px 16px;
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.team-board__title {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
}

.team-board__desc {
  font-size: 12px;
  color: var(--text-dim);
  margin-top: 2px;
}

.team-board__body {
  flex: 1;
  overflow-y: auto;
  padding: 16px;
}

.team-board__section {
  margin-bottom: 20px;
}

.team-board__section-title {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-bottom: 8px;
}

.team-task {
  display: flex;
  align-items: flex-start;
  gap: 8px;
  padding: 8px 10px;
  border: 1px solid var(--border);
  border-radius: 4px;
  margin-bottom: 4px;
}

.team-task__status-icon {
  flex-shrink: 0;
  font-size: 14px;
  margin-top: 1px;
}

.team-task__status-icon--completed {
  color: var(--ongoing);
}

.team-task__status-icon--in_progress {
  color: var(--accent);
}

.team-task__status-icon--pending {
  color: var(--text-muted);
}

.team-task__content {
  flex: 1;
  min-width: 0;
}

.team-task__subject {
  font-size: 12px;
  color: var(--text-primary);
}

.team-task__owner {
  font-size: 11px;
  color: var(--text-dim);
  margin-top: 1px;
  display: inline-flex;
  align-items: center;
  gap: 2px;
}

.team-task__status-badge {
  display: inline-flex;
  padding: 1px 6px;
  border-radius: 3px;
  font-size: 10px;
  font-weight: 600;
  flex-shrink: 0;
}

.team-task__status-badge--completed {
  background: rgba(135, 215, 135, 0.15);
  color: var(--ongoing);
}

.team-task__status-badge--in_progress {
  background: rgba(95, 175, 255, 0.15);
  color: var(--accent);
}

.team-task__status-badge--pending {
  background: rgba(88, 88, 88, 0.15);
  color: var(--text-muted);
}

.team-member {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 4px 8px;
  border: 1px solid var(--border);
  border-radius: 4px;
  margin-right: 6px;
  margin-bottom: 4px;
  font-size: 12px;
}

.team-member__dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}

.team-member__name {
  color: var(--text-primary);
}

.team-member__ongoing {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  background: var(--ongoing);
  animation: pulse 1.5s ease-in-out infinite;
}

/* ---- Debug Viewer ---- */

.debug-viewer {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.debug-viewer__header {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 8px 16px;
  background: var(--bg-surface);
  border-bottom: 1px solid var(--border);
  flex-shrink: 0;
}

.debug-viewer__title {
  font-weight: 600;
  font-size: 13px;
  color: var(--text-primary);
}

.debug-viewer__filter-group {
  display: flex;
  gap: 2px;
}

.debug-viewer__filter-btn {
  padding: 2px 8px;
  border: 1px solid var(--border);
  background: none;
  color: var(--text-dim);
  font-family: inherit;
  font-size: 11px;
  cursor: pointer;
  transition:
    background 0.1s,
    color 0.1s;
}

.debug-viewer__filter-btn:first-child {
  border-radius: 3px 0 0 3px;
}

.debug-viewer__filter-btn:last-child {
  border-radius: 0 3px 3px 0;
}

.debug-viewer__filter-btn--active {
  background: var(--accent);
  border-color: var(--accent);
  color: #fff;
}

.debug-viewer__search {
  flex: 1;
  max-width: 250px;
  padding: 3px 8px;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 3px;
  color: var(--text-primary);
  font-family: inherit;
  font-size: 11px;
  outline: none;
}

.debug-viewer__search:focus {
  border-color: var(--accent);
}

.debug-viewer__count {
  font-size: 11px;
  color: var(--text-muted);
  margin-left: auto;
}

.debug-viewer__body {
  flex: 1;
  overflow-y: auto;
  padding: 4px 0;
}

.debug-entry {
  padding: 3px 16px;
  font-size: 11px;
  cursor: pointer;
  transition: background 0.1s;
  display: flex;
  align-items: flex-start;
  gap: 8px;
}

.debug-entry:hover {
  background: var(--bg-hover);
}

.debug-entry--selected {
  background: var(--bg-elevated);
}

.debug-entry__timestamp {
  color: var(--text-muted);
  flex-shrink: 0;
  width: 80px;
}

.debug-entry__level {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  min-width: 42px;
  padding: 0 4px;
  border-radius: 2px;
  font-size: 10px;
  font-weight: 600;
  flex-shrink: 0;
  text-transform: uppercase;
}

.debug-entry__level--debug {
  background: rgba(95, 175, 255, 0.12);
  color: var(--accent);
}

.debug-entry__level--info {
  background: rgba(135, 215, 135, 0.12);
  color: var(--context-ok);
}

.debug-entry__level--warn {
  background: rgba(255, 135, 0, 0.12);
  color: var(--context-warn);
}

.debug-entry__level--error {
  background: rgba(255, 0, 0, 0.12);
  color: var(--error);
}

.debug-entry__category {
  color: var(--text-dim);
  flex-shrink: 0;
  width: 80px;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.debug-entry__message {
  flex: 1;
  color: var(--text-secondary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.debug-entry__count {
  color: var(--text-muted);
  flex-shrink: 0;
  font-size: 10px;
}

.debug-entry__extra {
  padding: 4px 16px 4px 108px;
  font-size: 11px;
  color: var(--text-dim);
  white-space: pre-wrap;
  word-break: break-all;
  background: var(--bg-surface);
  border-left: 2px solid var(--border);
  margin-left: 16px;
}

/* ---- Utility ---- */

.spinner {
  display: inline-block;
  font-size: 14px;
  animation: spin 0.8s linear infinite;
}

.dot-separator {
  color: var(--text-muted);
}

.empty-state {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  gap: 8px;
  color: var(--text-muted);
}

.empty-state__icon {
  font-size: 32px;
  opacity: 0.4;
  display: inline-flex;
  align-items: center;
}

.empty-state__icon svg {
  width: 32px;
  height: 32px;
}

.empty-state__text {
  font-size: 14px;
}

/* ---- View Transitions ---- */

.view-enter {
  opacity: 0;
}

.view-active {
  opacity: 1;
  transition: opacity 0.15s ease-in;
}

/* Split layout for detail view with agent panel */
.message-detail--split {
  flex-direction: row;
  overflow: hidden;
}

.message-detail__main {
  display: flex;
  flex-direction: column;
  flex: 1;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
}

.message-detail--split .message-detail__main {
  flex: 1 1 0;
  min-width: 200px;
}

/* Ensure body scrolls within main pane */
.message-detail__main .message-detail__body {
  flex: 1;
  overflow-y: auto;
  min-height: 0;
}

/* Panel chevron for subagent items with messages */
.detail-item__chevron--panel {
  color: var(--agent-panel);
}

/* Active subagent highlight in left pane */
.detail-item--agent-active {
  background: color-mix(in srgb, var(--agent-panel) 8%, transparent);
  border-left: 2px solid var(--agent-panel);
}

/* Focused column indicator */
.message-detail__main--focused {
  outline: 1px solid var(--accent);
  outline-offset: -1px;
}

.agent-panel--focused {
  outline: 1px solid var(--accent);
  outline-offset: -1px;
}

/* Agent panel — reuses .message classes, tinted background */
.agent-panel {
  flex: 1 1 0;
  min-width: 200px;
  min-height: 0;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  background: color-mix(in srgb, var(--agent-panel) 3%, transparent);
}

.agent-panel__header {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 10px 16px;
  border-bottom: 1px solid var(--border);
  background: color-mix(in srgb, var(--agent-panel) 6%, transparent);
  flex-shrink: 0;
  font-size: 12px;
  min-width: 0;
}

.agent-panel__close {
  background: none;
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  font-size: 18px;
  padding: 2px 6px;
  border-radius: 3px;
  display: inline-flex;
  align-items: center;
}

.agent-panel__close:hover {
  background: var(--bg-hover);
  color: var(--text-primary);
}

.agent-panel__icon {
  font-size: 13px;
  display: inline-flex;
  align-items: center;
}

.agent-panel__icon svg {
  width: 13px;
  height: 13px;
}

.agent-panel__type {
  font-weight: 600;
  color: #63b3ed;
}

.agent-panel__id {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--text-dim);
  opacity: 0.7;
  margin-left: auto;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  min-width: 0;
  flex-shrink: 1;
}

.agent-panel__desc {
  flex: 1;
  min-width: 0;
  color: var(--text-dim);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.agent-panel__stats {
  display: flex;
  gap: 8px;
  font-size: 11px;
  color: var(--text-dim);
  flex-shrink: 0;
}

.agent-panel__content {
  flex: 1;
  min-height: 0;
  min-width: 0;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

.agent-panel__list {
  display: flex;
  flex-direction: column;
  flex: 1;
  overflow-y: auto;
  min-height: 0;
  min-width: 0;
}

/* Messages inside agent panel get a slightly lighter background for readability */
.agent-panel .message {
  background: rgba(255, 255, 255, 0.02);
}

.agent-panel .message--selected {
  background: rgba(99, 179, 237, 0.08);
}

/* Agent panel content needs scrollable body */
.agent-panel .message-detail__body {
  flex: 1;
  overflow-y: auto;
  min-height: 0;
}

/* ============================================================
   Settings Modal
   ============================================================ */

.settings-modal__title {
  font-weight: 600;
  color: var(--text-primary);
}

.settings-modal {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 12px 16px;
}

.settings-modal__label {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-secondary);
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.settings-modal__input {
  width: 100%;
  padding: 6px 8px;
  background: var(--bg);
  border: 1px solid var(--border);
  border-radius: 4px;
  color: var(--text-primary);
  font-family: inherit;
  font-size: 13px;
  box-sizing: border-box;
  outline: none;
}

.settings-modal__input:focus {
  border-color: var(--accent);
}

.settings-modal__hint {
  margin: 0;
  font-size: 11px;
  color: var(--text-dim);
}

.settings-modal__error {
  margin: 0;
  font-size: 12px;
  color: var(--error);
}

.settings-modal__actions {
  display: flex;
  gap: 8px;
  justify-content: flex-end;
  margin-top: 4px;
}

.settings-modal__btn {
  padding: 4px 12px;
  border: 1px solid var(--border);
  border-radius: 4px;
  font-size: 12px;
  cursor: pointer;
  background: var(--bg-elevated);
  color: var(--text-primary);
}

.settings-modal__btn:hover:not(:disabled) {
  background: var(--bg-hover);
}

.settings-modal__btn:disabled {
  opacity: 0.4;
  cursor: default;
}

.settings-modal__btn--primary {
  background: var(--accent);
  border-color: var(--accent);
  color: #fff;
}

.settings-modal__btn--primary:hover:not(:disabled) {
  background: #4a9aee;
}

