/* ============================================================
   claude-code-trace — Dark theme matching the Go TUI
   ============================================================ */

:root {
  /* Background */
  --bg: #1a1a2e;
  --bg-surface: #16213e;
  --bg-elevated: #222244;
  --bg-hover: #2a2a4a;

